logger.message:
#[%dw 2.0
output application/json
---
{
    appName: app.name,
    flowName : flow.name,
    position: "Flow End",
    message: {
    	payload: payload
    },
    correlationId: vars.'correlationId',
    timeStamp: now() as DateTime as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", timezone: "UTC"}
}]
